from smolagents import Agent
import time

def safe_agent_run(agent, max_steps=10, max_time=60):
    start_time = time.time()
    step_count = 0

    def run_with_guard(prompt):
        nonlocal step_count

        while step_count < max_steps and (time.time() - start_time) < max_time:
            step_count += 1
            try:
                result = agent.run(prompt)
                if 'final answer' in result.lower() or len(result) > 500:
                    return result
            except Exception:
                return 'Operation timed out for cost control.'

        return 'Max steps reached - cost limit enforced.'

    return run_with_guard

safe_run = safe_agent_run(my_agent)

